#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    string solve(string& s) {
        // Remove spaces from the string
        string t;
        for(char c: s) if(c!=' ') t.push_back(c);
        // Collect digits
        vector<int> digits;
        for(char c: t) if(isdigit(c)) digits.push_back(c - '0');
        if(digits.empty()) return "-1";
        vector<int> oddDigits;
        for(int d: digits) if(d % 2 == 1) oddDigits.push_back(d);
        if(oddDigits.empty()) return "-1";
        sort(digits.begin(), digits.end(), greater<int>());
        int smallestOdd = *min_element(oddDigits.begin(), oddDigits.end());
        // Remove one occurrence of smallestOdd from digits
        for(int i = (int)digits.size() - 1; i >= 0; --i) {
            if(digits[i] == smallestOdd) {
                digits.erase(digits.begin() + i);
                break;
            }
        }
        digits.push_back(smallestOdd);
        string res;
        for(int d: digits) res.push_back('0' + d);
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    string line;
    // Read first non‑empty line as the string
    while (getline(cin, line)) {
        if (!line.empty()) break;
    }
    if(line.empty()) return 0;
    Solution sol;
    string ans = sol.solve(line);
    cout << ans << "\n";
    return 0;
}
